CREATE TABLE "integrity_chain_records" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"fiscal_document_id" uuid NOT NULL REFERENCES "fiscal_documents"("id"),"record_type" text NOT NULL,"canonical_payload" text NOT NULL,"previous_hash" text,"hash" text NOT NULL,"algorithm" text NOT NULL DEFAULT 'SHA-256');
CREATE UNIQUE INDEX "integrity_hash_uq" ON "integrity_chain_records"("tenant_id","hash");
CREATE TABLE "verifactu_submissions" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"integrity_record_id" uuid NOT NULL REFERENCES "integrity_chain_records"("id"),"environment" text NOT NULL,"status" text NOT NULL,"payload_redacted" jsonb NOT NULL,"response_redacted" jsonb,"attempt_count" numeric(8,0) NOT NULL DEFAULT 0);
CREATE TABLE "period_closes" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"period" text NOT NULL,"status" text NOT NULL,"frozen_at" timestamptz,"approved_by" uuid REFERENCES "users"("id"),"blocking_approval_id" uuid);
CREATE UNIQUE INDEX "period_close_uq" ON "period_closes"("tenant_id","period");
CREATE TABLE "vat_dossiers" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),"created_at" timestamptz NOT NULL DEFAULT now(),"updated_at" timestamptz NOT NULL DEFAULT now(),"tenant_id" uuid NOT NULL REFERENCES "tenants"("id"),"period_close_id" uuid NOT NULL REFERENCES "period_closes"("id"),"schema_version" text NOT NULL,"status" text NOT NULL,"storage_key" text NOT NULL,"archive_sha256" text NOT NULL,"manifest" jsonb NOT NULL);
